 13→class MixedIterablePyNodeTest {
 14→
 15→    // Helper method to create a PyIntNode with given domains
 16→    private static PyIntNode createIntNode(List<Integer> exDomain, List<Integer> ranDomain) {
 17→        PyIntNode node = new PyIntNode();
 18→        node.setExDomain(new ArrayList<>(exDomain));
 19→        node.setRanDomain(new ArrayList<>(ranDomain));
 20→        return node;
 21→    }
 22→
 23→    /**
 24→     * Test a complex nested structure: List of Tuples of Ints
 25→     * This tests that different iterable types can be properly nested.
 26→     */
 27→    @Test
 28→    void testListOfTuplesExhaustive() {
 29→        // Create int node
 30→        PyIntNode intNode = createIntNode(Arrays.asList(1, 2), Arrays.asList(1, 2));
 31→
 32→        // Create tuple node containing ints
 33→        PyTupleNode<PyIntObj> tupleNode = new PyTupleNode<>(intNode);
 34→        tupleNode.setExDomain(Arrays.asList(1)); // Tuples of length 1
 35→
 36→        // Create list node containing tuples
 37→        PyListNode<PyTupleObj<PyIntObj>> listNode = new PyListNode<>(tupleNode);
 38→        listNode.setExDomain(Arrays.asList(2)); // Lists of length 2
 39→
 40→        Set<PyListObj<PyTupleObj<PyIntObj>>> result = listNode.genExVals();
 41→
 42→        // Inner tuples: (1,) or (2,) = 2 options
 43→        // Outer list has length 2, allowing duplicates
 44→        // So: [[1], [1]], [[1], [2]], [[2], [1]], [[2], [2]] = 4 results
 45→        assertEquals(4, result.size());
 46→
 47→        // Verify structure
 48→        for (PyListObj<PyTupleObj<PyIntObj>> list : result) {
 49→            assertEquals(2, list.getValue().size());
 50→            for (PyTupleObj<PyIntObj> tuple : list.getValue()) {
 51→                assertEquals(1, tuple.getValue().size());
 52→            }
 53→        }
 54→    }
 55→
 56→    /**
 57→     * Test a complex nested structure with randomness: Dict with List values
 58→     * This verifies that nested random generation works correctly.
 59→     */
 60→    @Test
 61→    void testDictWithListValuesRandom() {
 62→        // Create key node (ints)
 63→        PyIntNode keyNode = createIntNode(Arrays.asList(1, 2, 3), Arrays.asList(1, 2, 3));
 64→
 65→        // Create inner int node for list elements
 66→        PyIntNode innerIntNode = createIntNode(Arrays.asList(10, 20), Arrays.asList(10, 20, 30));
 67→
 68→        // Create list node for values
 69→        PyListNode<PyIntObj> listValNode = new PyListNode<>(innerIntNode);
 70→        listValNode.setRanDomain(Arrays.asList(0, 1, 2)); // Lists of length 0-2
 71→
 72→        // Create dict node
 73→        PyDictNode<PyIntObj, PyListObj<PyIntObj>> dictNode = new PyDictNode<>(keyNode, listValNode);
 74→        dictNode.setRanDomain(Arrays.asList(1, 2)); // Dicts of size 1-2
 75→
 76→        // Generate multiple random values and verify structure
 77→        for (int i = 0; i < 50; i++) {
 78→            PyDictObj<PyIntObj, PyListObj<PyIntObj>> result = dictNode.genRandVal();
 79→
 80→            // Dict size should be 1 or 2
 81→            int dictSize = result.getValue().size();
 82→            assertTrue(dictSize >= 1 && dictSize <= 2,
