    private final String chars;
    private final Random random = new Random();

    public PyStringNode(String chars) {
        super(null);
        this.chars = chars;
    }

    @Override
    public APyNode<PyCharObj> getLeftChild() {
        return null;
    }

    @Override
    public Set<PyStringObj> genExVals() {
        List<PyCharObj> charList = new ArrayList<>();
        for (int i = 0; i < this.chars.length(); i++) {
            charList.add(new PyCharObj(this.chars.charAt(i)));
        }

        Set<PyStringObj> result = new HashSet<>();
        for (int length : this.exDomain) {
            if (length == 0) {
                result.add(new PyStringObj(""));
            } else {
                List<List<PyCharObj>> sequences = allSequences(charList, length);
                for (List<PyCharObj> seq : sequences) {
                    result.add(new PyStringObj(seq));
                }
            }
        }
        return result;
    }

    @Override
    public PyStringObj genRandVal() {
        int length = this.ranDomain.get(this.random.nextInt(this.ranDomain.size()));
        List<PyCharObj> elements = new ArrayList<>();
        for (int i = 0; i < length; i++) {
            elements.add(new PyCharObj(this.chars.charAt(
                    this.random.nextInt(this.chars.length()))));
        }
        return new PyStringObj(elements);
    }

    private static <T> List<List<T>> allSequences(List<T> elements, int length) {
        List<List<T>> result = new ArrayList<>();
        allSequencesHelper(elements, length, new ArrayList<>(), result);
        return result;
    }

    private static <T> void allSequencesHelper(List<T> elements, int length,
            List<T> current, List<List<T>> result) {
        if (current.size() == length) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (T elem : elements) {
            current.add(elem);
            allSequencesHelper(elements, length, current, result);
            current.remove(current.size() - 1);
        }
    }
}

package main.rice.node;

import main.rice.obj.APyObj;
import main.rice.obj.PyDictObj;
import java.util.*;

/**
 * A node for generating Python dictionary values. Has both a left child
 * (key generator) and a right child (value generator). The exhaustive and
 * random domains represent the possible sizes of the generated dictionaries.
 * Dictionaries have unique keys.
 *
 * @param <KeyType> the type of keys in the dictionary
 * @param <ValType> the type of values in the dictionary
 */
public class PyDictNode<KeyType extends APyObj, ValType extends APyObj>
        extends APyNode<PyDictObj<KeyType, ValType>> {

    private final APyNode<KeyType> leftChild;
    private final APyNode<ValType> rightChild;
    private final Random random = new Random();

    public PyDictNode(APyNode<KeyType> keyNode, APyNode<ValType> valNode) {
        this.leftChild = keyNode;
        this.rightChild = valNode;
    }

    @Override
    public APyNode<KeyType> getLeftChild() {
        return this.leftChild;
    }

    @Override
    public APyNode<ValType> getRightChild() {
        return this.rightChild;
    }

    @Override
    public Set<PyDictObj<KeyType, ValType>> genExVals() {
        Set<KeyType> keySet = this.leftChild.genExVals();
        Set<ValType> valSet = this.rightChild.genExVals();
        List<KeyType> keys = new ArrayList<>(keySet);
        List<ValType> vals = new ArrayList<>(valSet);

        Set<PyDictObj<KeyType, ValType>> result = new HashSet<>();

        for (int size : this.exDomain) {
            if (size == 0) {
                result.add(new PyDictObj<>(new HashMap<>()));
            } else {
                // Generate all combinations of `size` keys (unique keys)
                List<List<KeyType>> keyCombos = allCombinations(keys, size);

                for (List<KeyType> keyCombo : keyCombos) {
                    // For each key combination, generate all value assignments
                    List<List<ValType>> valSequences = allSequences(vals, size);
                    for (List<ValType> valSeq : valSequences) {
                        Map<KeyType, ValType> map = new HashMap<>();
                        for (int i = 0; i < size; i++) {
                            map.put(keyCombo.get(i), valSeq.get(i));
                        }
                        result.add(new PyDictObj<>(map));
                    }
                }
            }
        }
        return result;
    }

    @Override
    public PyDictObj<KeyType, ValType> genRandVal() {
        int size = this.ranDomain.get(this.random.nextInt(this.ranDomain.size()));
        Map<KeyType, ValType> map = new HashMap<>();
        int maxAttempts = size * 100;
        int attempts = 0;
        while (map.size() < size && attempts < maxAttempts) {
            KeyType key = this.leftChild.genRandVal();
            if (!map.containsKey(key)) {
                ValType val = this.rightChild.genRandVal();
                map.put(key, val);
            }
            attempts++;
        }
        return new PyDictObj<>(map);
    }

    private static <T> List<List<T>> allCombinations(List<T> elements, int k) {
        List<List<T>> result = new ArrayList<>();
        allCombinationsHelper(elements, k, 0, new ArrayList<>(), result);
        return result;
    }

    private static <T> void allCombinationsHelper(List<T> elements, int k, int start,
            List<T> current, List<List<T>> result) {
        if (current.size() == k) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (int i = start; i < elements.size(); i++) {
            current.add(elements.get(i));
            allCombinationsHelper(elements, k, i + 1, current, result);
            current.remove(current.size() - 1);
        }
    }

    private static <T> List<List<T>> allSequences(List<T> elements, int length) {
        List<List<T>> result = new ArrayList<>();
        allSequencesHelper(elements, length, new ArrayList<>(), result);
        return result;
    }

    private static <T> void allSequencesHelper(List<T> elements, int length,
            List<T> current, List<List<T>> result) {
        if (current.size() == length) {
            result.add(new ArrayList<>(current));
            return;
        }
        for (T elem : elements) {
            current.add(elem);
            allSequencesHelper(elements, length, current, result);
            current.remove(current.size() - 1);
        }
    }
}

